// Simplified pseudocode: gateway receives WS message and publishes to Kafka
func handleWSMessage(conn *WSConn, msg Message) {
    // assign a globally unique message ID
    msg.ID = generateID()

    // produce to Kafka topic for server/guild partitioning
    kafkaProducer.Produce(ctx, &sarama.ProducerMessage{
        Topic: "messages",
        Key:   sarama.StringEncoder(msg.GuildID), // partitions by guild
        Value: sarama.ByteEncoder(serialize(msg)),
    })

    // ack to sender quickly
    conn.WriteJSON(Ack{ID: msg.ID, Status: "accepted"})
}

// Consumer side: apply and deliver
func messageConsumerLoop() {
    for m := range kafkaConsumer.Messages() {
        msg := deserialize(m.Value)
        // idempotent write to shard
        writeToShard(msg.GuildID, msg)
        // publish back to gateways (they subscribe to Kafka to push to connected clients)
        outgoingProducer.Produce(...)
    }
}
