// Go example using singleflight to avoid cache stampede (pseudo)
package main

import (
  "context"
  "encoding/json"
  "time"
  "golang.org/x/sync/singleflight"
)

var g singleflight.Group

func GetProduct(ctx context.Context, id string) (*Product, error) {
  key := "product:" + id
  if v := redisGet(key); v != nil {
    var p Product
    json.Unmarshal(v, &p)
    return &p, nil
  }

  // singleflight ensures only one DB load for this key at a time
  val, err, _ := g.Do(key, func() (interface{}, error) {
    p, err := dbLoadProduct(id)
    if err != nil { return nil, err }
    b, _ := json.Marshal(p)
    redisSetEx(key, b, 60*time.Second)
    return p, nil
  })
  if err != nil { return nil, err }
  return val.(*Product), nil
}
